function pointers_valid_palindrome(nums) {
  let left = 0;
  let right = nums.length - 1;

  while (left < right) {
    // compare or swap based on nums[left] and nums[right]
    if (/* condition met */) {
      left++;
      right--;
    } else if (/* move left */) {
      left++;
    } else {
      right--;
    }
  }
  return /* answer */;
}

