function slow_pointers_ext_detect_loop_in_linked_list(head) {
  let slow = head;
  let fast = head;

  while (fast && fast.next) {
    slow = slow.next;
    fast = fast.next.next;
    if (slow === fast) return true; // cycle
  }
  return false;
}

